ee:variables.ee:set-variable:
%dw 2.0
output application/java

var sfById    = (vars.sfAccounts   default []) groupBy ($.Id)
var erpBySfId = (vars.erpCustomers default []) groupBy ($.custom_salesforce_id)

var missingInERP = (vars.sfAccounts default []) filter (sfRec) ->
    erpBySfId[sfRec.Id] == null

var staleInERP = (vars.sfAccounts default []) filter (sfRec) -> do {
    var match = (erpBySfId[sfRec.Id] default [null])[0]
    ---
    match != null and (
        (match.customer_name default "") != (sfRec.Name    default "") or
        (match.mobile_no     default "") != (sfRec.Phone   default "") or
        (match.website       default "") != (sfRec.Website default "")
    )
}

// ERP record has a SF ID but no active SF Account — most likely the SF Account
// was deleted while ERP was unreachable and the DELETE CDC event was lost
var orphanedInERP = (vars.erpCustomers default []) filter (erpRec) ->
    sfById[erpRec.custom_salesforce_id] == null
---
{
    missingInERP:  missingInERP,
    staleInERP:    staleInERP,
    orphanedInERP: orphanedInERP,
    summary: {
        totalSF:       sizeOf(vars.sfAccounts   default []),
        totalERP:      sizeOf(vars.erpCustomers default []),
        missingCount:  sizeOf(missingInERP),
        staleCount:    sizeOf(staleInERP),
        orphanedCount: sizeOf(orphanedInERP)
    }
}
